import pytest

def topological_sort(graph: dict) -> list:
    visited = set()
    result = []
    def dfs(node):
        if node in visited:
            return
        visited.add(node)
        for neighbor in graph.get(node, []):
            dfs(neighbor)
        result.append(node)
    for node in graph:
        dfs(node)
    return result[::-1]

