        """Test with single node and no edges"""
        graph = {'A': []}
        result = topological_sort(graph)
        assert result == ['A']

    def test_single_node_self_reference(self):
        """Test with single node that references itself"""
        graph = {'A': ['A']}
        # This will cause infinite recursion due to cycle
        with pytest.raises(RecursionError):
            topological_sort(graph)

    def test_linear_chain(self):
        """Test with linear dependency chain"""
        graph = {
